parameters.jsCode:
const items = $input.all();

if (items.length === 0) {
  const busqueda = $('Ejecutar Workflow').item.json.codigo_inmueble ?? 'desconocido';
  return [{ json: { id: null, resultado: '🔍 No se encontró ningún inmueble activo para: *' + busqueda + '*. Verifica el código o la dirección.' } }];
}

if (items.length === 1) {
  return [{ json: { ...items[0].json, resultado: null } }];
}

// Múltiples resultados
const lista = items.map((it, i) => {
  const p = it.json;
  return (i + 1) + '. *' + p.code + '* - ' + p.property_type + ' en ' + p.address + ' ($' + Number(p.price).toLocaleString('es-EC') + ')';
}).join('\n');

return [{
  json: {
    id: null,
    resultado: '🏠 Encontré ' + items.length + ' inmuebles para tu búsqueda:\n\n' + lista + '\n\n¿A cuál te refieres? Indícame el código exacto (ej: ST-001).'
  }
}];

